import classnames from 'classnames';
import React, { useEffect, useState } from 'react';

import { CLASS_IS_ACTIVE } from './SuccessBannerBase.constants';
import { Wrapper } from './SuccessBannerBase.styles';
import { Props } from './SuccessBannerBase.types';

const SuccessBannerBase: React.FC<Props> = ({
  messageTimeout = 8000,
  className,
  ...rest
}) => {
  const [isActive, setIsActive] = useState(false);

  useEffect(() => {
    setIsActive(true);
    const timeoutId = setTimeout(() => setIsActive(false), messageTimeout);
    return () => clearTimeout(timeoutId);
  }, [messageTimeout]);

  return (
    <Wrapper
      {...rest}
      className={classnames(className, { [CLASS_IS_ACTIVE]: isActive })}
    />
  );
};

export default SuccessBannerBase;
